#include <vector>
#include <queue>
#include <utility>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0];
        long long v = e[1];
        long long cost = e[2];
        adj[u].push_back({v, cost});
    }

    vector<long long> max_min(n, -LLONG_MAX);
    max_min[0] = LLONG_MAX;

    priority_queue<tuple<long long, long long, int>> pq;
    pq.push( { -LLONG_MAX, 0, 0 } );

    while (!pq.empty()) {
        auto [neg_curr_min, total, u] = pq.top();
        pq.pop();
        long long curr_min = -neg_curr_min;

        if (u == n-1) {
            return curr_min;
        }

        for (auto& [v, cost] : adj[u]) {
            if (!online[v]) continue;
            long long new_total = total + cost;
            if (new_total > k) continue;

            long long new_min = min(curr_min, cost);
            if (new_min > max_min[v]) {
                max_min[v] = new_min;
                pq.push( { -new_min, new_total, v } );
            }
        }
    }

    return -1;
}

