import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int cost = (int) edge[2];
            adj.get(u).add(new int[]{v, cost});
        }

        long[] max_min = new long[n];
        Arrays.fill(max_min, -Long.MAX_VALUE);
        max_min[0] = Long.MAX_VALUE;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{-Long.MAX_VALUE, 0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long neg_curr_min = current[0];
            long total = current[1];
            int u = current[2];
            long curr_min = -neg_curr_min;

            if (u == n - 1) {
